def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        if ratio > 1:
            priorities[i] = ratio ** 4 + np.log1p(ratio)
        elif ratio == 1:
            priorities[i] = 0
        else:
            score = 0
            for j in range(1, 6):
                if j % 2 == 0:
                    score += (ratio ** j) / (j * 2)
                else:
                    score += (ratio ** j) / j
            if bin_capacity < item * 1.5:
                score *= 2
            elif bin_capacity < item * 3:
                score *= 1.2
            else:
                for k in range(1, 4):
                    score += (ratio / (k + 1)) ** k
            priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 3
        elif priorities[i] < 0:
            priorities[i] = 0
    for i in range(len(priorities)):
        for j in range(i + 1, len(priorities)):
            if priorities[j] < priorities[i]:
                priorities[i], priorities[j] = priorities[j], priorities[i]
    return priorities
